import { Component, Prop, h, Element, Host, Event, EventEmitter } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

export type OverlayRole = 'region' | 'dialog';
export type OverlayVariant = 'surface' | 'scrim';

@Component({
  tag: 'wdpr-overlay',
  shadow: true,
})
export class WdprOverlay {
  @Element() el!: HTMLElement;

  @Prop() open = false;
  @Prop() overlayRole: OverlayRole = 'region';
  @Prop() overlayStyle?: 'light' | 'disabled' | 'default' = 'default';
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;
  @Prop({ reflect: true }) cover = false;
  @Prop() zIndex: number = 10;

  /** surface = your card-like surface; scrim = full-bleed backdrop */
  @Prop() variant: OverlayVariant = 'surface';

  /** Background class for the overlay */
  @Prop() bgClass?: string;

  /** Click on empty overlay area */
  @Event({ eventName: 'overlayClick' }) overlayClick!: EventEmitter<void>;

  private onSurfaceClick = (e: MouseEvent) => {
    if (e.target === e.currentTarget) this.overlayClick.emit();
  };

  private get surfaceClass() {
    const base = this.cover
      ? 'absolute inset-0 w-full h-full box-border flex flex-col'
      : 'inline-flex flex-col';

    const visible = this.open ? 'opacity-1250 pointer-events-auto' : 'hidden opacity-000 pointer-events-none';

    if (this.variant === 'scrim') {
      const bg = this.bgClass ?? 'bg-page-overlay';

      return customTwMerge(base, 'justify-center items-center rounded-000', bg, visible);
    }

    const overlayStyleMap: Record<string, string> = {
      light: 'bg-page-overlay-light',
      disabled: 'bg-page-overlay-disabled',
      default: 'bg-page-overlay',
    };

    const bg = this.overlayStyle && overlayStyleMap[this.overlayStyle]
      ? `${overlayStyleMap[this.overlayStyle]} ${this.bgClass ?? ''}`
      : this.bgClass ?? 'bg-page-overlay';

    return customTwMerge(
      base,
      bg,
      visible,
      this.cover ? 'rounded-000' : '',
      'justify-end p-100 items-start gap-100',
    );
  }

  render() {
    return (
      <Host aria-hidden={this.open ? 'false' : 'true'} style={this.cover ? { zIndex: String(this.zIndex) } : {}}>
        <div
          class={this.surfaceClass}
          role={this.overlayRole}
          aria-label={this.a11yLabel}
          onClick={this.onSurfaceClick}
        >
          <slot />
        </div>
      </Host>
    );
  }
}
